import React, { useState } from 'react';
import { Lock, User, Zap, Mail, UserPlus, ArrowRight, ShieldCheck } from 'lucide-react';

const Login = ({ onLogin, onRegister }) => {
  const [isRegister, setIsRegister] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    setError('');

    if (isRegister) {
      // Registration Logic
      const users = JSON.parse(localStorage.getItem('mulani_users') || '[]');
      if (users.find(u => u.email === email)) {
        setError('User already exists with this email');
        return;
      }

      const newUser = {
        name,
        email,
        password,
        role: 'user',
        id: Date.now().toString()
      };

      users.push(newUser);
      localStorage.setItem('mulani_users', JSON.stringify(users));
      onLogin(newUser);
    } else {
      // Login Logic
      // Check Admin
      const adminEmail = localStorage.getItem('admin_email') || 'mh15sohail@gmail.com';
      const adminPass = localStorage.getItem('admin_password') || '16301003';

      if (email === adminEmail && password === adminPass) {
        onLogin({ name: 'Sohail Mulani', email: adminEmail, role: 'admin' });
        return;
      }

      // Check Regular Users
      const users = JSON.parse(localStorage.getItem('mulani_users') || '[]');
      const user = users.find(u => u.email === email && u.password === password);

      if (user) {
        onLogin(user);
      } else {
        setError('Invalid email or password');
      }
    }
  };

  return (
    <div className="max-w-lg mx-auto mt-12 mb-20 animate-in fade-in zoom-in-95 duration-500">
      <div className="glass p-10 md:p-14 rounded-[3.5rem] border border-white/10 shadow-2xl relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 gold-gradient"></div>

        <div className="flex flex-col items-center mb-10">
          <div className="bg-yellow-500 p-4 rounded-2xl mb-6 shadow-[0_0_30px_rgba(234,179,8,0.4)] rotate-3">
            <Zap className="text-black" size={32} fill="currentColor" />
          </div>
          <h2 className="text-4xl font-black gold-text-gradient uppercase tracking-tighter text-center">
            {isRegister ? 'Create Account' : 'Welcome Back'}
          </h2>
          <p className="text-gray-500 mt-2 text-sm font-bold uppercase tracking-widest">
            {isRegister ? 'Join Mulani Electricals' : 'Premium Access Portal'}
          </p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-5">
          {isRegister && (
            <div className="space-y-2">
              <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] ml-2">Full Name</label>
              <div className="relative group">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-yellow-500 transition-colors" size={18} />
                <input
                  type="text"
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 focus:border-yellow-500 outline-none transition-all font-medium text-white"
                  placeholder="Enter your name"
                  required
                />
              </div>
            </div>
          )}

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] ml-2">Email Address</label>
            <div className="relative group">
              <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-yellow-500 transition-colors" size={18} />
              <input
                type="email"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 focus:border-yellow-500 outline-none transition-all font-medium text-white"
                placeholder="your@email.com"
                required
              />
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-[10px] font-black text-gray-500 uppercase tracking-[0.2em] ml-2">Secure Password</label>
            <div className="relative group">
              <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-500 group-focus-within:text-yellow-500 transition-colors" size={18} />
              <input
                type="password"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-2xl py-4 pl-12 pr-4 focus:border-yellow-500 outline-none transition-all font-medium text-white"
                placeholder="••••••••"
                required
              />
            </div>
          </div>

          {error && (
            <div className="bg-red-500/10 border border-red-500/20 text-red-500 text-xs font-bold p-4 rounded-xl text-center animate-shake">
              {error}
            </div>
          )}

          <button
            type="submit"
            className="w-full py-5 gold-gradient rounded-[1.5rem] text-black font-black text-sm uppercase tracking-widest hover:shadow-[0_20px_40px_-10px_rgba(234,179,8,0.4)] transition-all flex items-center justify-center gap-2 group mt-4"
          >
            {isRegister ? 'Register Now' : 'Sign In'}
            <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
          </button>
        </form>

        <div className="mt-10 pt-8 border-t border-white/5 text-center flex flex-col gap-4">
          <p className="text-gray-500 text-xs font-bold">
            {isRegister ? 'Already have an account?' : "Don't have an account?"}
            <button
              onClick={() => { setIsRegister(!isRegister); setError(''); }}
              className="text-yellow-500 hover:text-white transition-colors ml-2 uppercase tracking-widest"
            >
              {isRegister ? 'Login Here' : 'Create Account'}
            </button>
          </p>

          {!isRegister && (
            <div className="flex items-center justify-center gap-2 text-[10px] text-gray-600 font-black uppercase tracking-widest">
              <ShieldCheck size={12} /> Secure Admin & User Login Enabled
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Login;
